INSERT INTO public.ai_tool VALUES (1, 'getAppDispatchList', '查询工单信息', '查询工单列表接口。当用户想要查看、查询、统计工单、订单、任务列表时调用此工具。支持按日期、状态、处理人等条件筛选。例如："查下我今天有多少单子"、"查看未处理的工单"、"显示我的待办任务"等场景。', NULL, NULL, NULL, '[{"key":"methodName","fieldType":"String","valueSource":"static","sourceValue":"getAppDispatchList","fieldKey":"","children":[]},{"key":"data","fieldType":"Object","valueSource":"static","sourceValue":"","fieldKey":"","children":[{"key":"orderStatu","fieldType":"String","valueSource":"static","sourceValue":"25,30,35,80,85,90,210","fieldKey":"","children":[]},{"key":"isSupplement","fieldType":"String","valueSource":"static","sourceValue":"0,3","fieldKey":"","children":[]},{"key":"queryPlanSortSql","fieldType":"String","valueSource":"static","sourceValue":" TMP.ETDL_ORDER_ARRIVAL_TIME, TMP.ETDL_TECH_RESERVATION_TIME, TMP.ETDL_ID","fieldKey":"","children":[]},{"key":"isDispatch","fieldType":"String","valueSource":"static","sourceValue":"0","fieldKey":"","children":[]},{"key":"pageSize","fieldType":"Number","valueSource":"static","sourceValue":"10","fieldKey":"","children":[]},{"key":"pageIndex","fieldType":"Number","valueSource":"static","sourceValue":"1","fieldKey":"","children":[]},{"key":"supplierCode","fieldType":"String","valueSource":"context","sourceValue":"","fieldKey":"esusMobile","children":[]},{"key":"endTimeFm","fieldType":"String","valueSource":"llm","sourceValue":"查询开始日期，格式 YYYY-MM-DD，默认今天","fieldKey":"","children":[]},{"key":"endTimeTo","fieldType":"String","valueSource":"llm","sourceValue":"查询结束日期，格式 YYYY-MM-DD，默认今天","fieldKey":"","children":[]}]}]', '[{"key":"returnCode","fieldType":"Number","label":"请求结果","description":"等于200，代表请求成功，其他则请求失败","children":[]},{"key":"info","fieldType":"String","label":"请求说明","description":"请求失败时，内容为失败信息","children":[]},{"key":"data","fieldType":"Array","label":"工单列表","description":"","children":[{"key":"STATUS_DISPLAY","fieldType":"String","label":"工单状态","description":"","children":[]},{"key":"WORK_NO","fieldType":"String","label":"工单号","description":"","children":[]},{"key":"ID","fieldType":"String","label":"工单ID","description":"","children":[]},{"key":"etdlDispatchRemake","fieldType":"String","label":"客户备注","description":"","children":[]},{"key":"GOODS_COUNT","fieldType":"String","label":"商品数量","description":"","children":[]},{"key":"COMPLETE_DATE","fieldType":"String","label":"完工时间","description":"","children":[]},{"key":"SEND_DATE","fieldType":"String","label":"派单时间","description":"","children":[]}]}]', '{"type":"object","properties":{"endTimeFm":{"type":"string","description":"查询开始日期，格式 YYYY-MM-DD，默认今天"},"endTimeTo":{"type":"string","description":"查询结束日期，格式 YYYY-MM-DD，默认今天"}},"required":[]}', true, '2026-04-17 10:17:55.049+08', '2026-04-21 10:05:43.854+08', 2);
